import os
import json
import uuid
import random
from datetime import datetime, timezone
from kafka import KafkaProducer

# ====== KAFKA ======
# ⚠️ Замени брокеры на нужный стенд (ИФТ/ПСИ/ПРОМ ПКАП)
BROKERS = ["tvldq-sber00010.delta.sbrf.ru:9092", "tvldq-sber00011.delta.sbrf.ru:9092"]
ZNO_TOPIC = "REPL.PKAP1173.911_ZNO"

# ⚠️ Тестовый префикс — НЕ ПЕРЕСЕКАЕТСЯ с реальными SR от ПКАП
ZNO_TEST_PREFIX = "SR9000000000"

# Локальный реестр отправленных тестовых SR (общий для INSERT/UPDATE-ноутбуков)
ZNO_REGISTRY_PATH = os.path.abspath("./zno_test_registry.json")

producer_kafka_config = {
    "bootstrap_servers": BROKERS,
    "security_protocol": "PLAINTEXT",
}


def get_byte_string(obj):
    if isinstance(obj, str):  return obj.encode("utf-8")
    if isinstance(obj, dict): return json.dumps(obj, ensure_ascii=False).encode("utf-8")
    if isinstance(obj, list): return json.dumps(obj, ensure_ascii=False).encode("utf-8")
    return str(obj).encode("utf-8")


def now_str():
    """UTC-время в формате 'YYYY-MM-DD HH:MM:SS.mmm'."""
    return datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M:%S.%f")[:-3]


def make_test_zno_id(suffix: int) -> str:
    """Тестовый business_id ЗНО, например: SR90000000000007."""
    return f"{ZNO_TEST_PREFIX}{suffix:04d}"


# ── Реестр ──────────────────────────────────────────────────────────────
def _load_registry() -> dict:
    if not os.path.exists(ZNO_REGISTRY_PATH):
        return {}
    try:
        with open(ZNO_REGISTRY_PATH, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {}


def _save_registry(reg: dict) -> None:
    with open(ZNO_REGISTRY_PATH, "w", encoding="utf-8") as f:
        json.dump(reg, f, ensure_ascii=False, indent=2)


def registry_put(record: dict) -> None:
    reg = _load_registry()
    reg[record["businessid"]] = record
    _save_registry(reg)


def registry_get(business_id: str) -> dict | None:
    return _load_registry().get(business_id)


def registry_list(prefix: str = ZNO_TEST_PREFIX, limit: int = 20) -> list[str]:
    reg = _load_registry()
    ids = [bid for bid in reg.keys() if bid.startswith(prefix)]
    ids.sort(reverse=True)
    return ids[:limit]


print("✅ Константы и утилиты загружены")
print(f"   Брокеры:        {BROKERS}")
print(f"   Топик ЗНО:      {ZNO_TOPIC}")
print(f"   Префикс тест.:  {ZNO_TEST_PREFIX}")
print(f"   Реестр:         {ZNO_REGISTRY_PATH}")

